mapper.update:
update store_menu_category set
	category_name = #{categoryName},
	display_order = #{displayOrder}
where menu_category_idx = #{menuCategoryIdx}
  and store_idx = #{storeIdx}

mapper.delete:
delete from store_menu_category
	where menu_category_idx = #{menuCategoryIdx}
	  and store_idx = #{storeIdx}
